import React from 'react';
import { motion } from 'framer-motion';
import { 
  ChevronDownIcon, 
  CodeBracketIcon, 
  CpuChipIcon, 
  CommandLineIcon,
  CheckCircleIcon,
  ArrowRightIcon,
  EnvelopeIcon,
  LinkIcon
} from '@heroicons/react/24/outline';
import { Link } from 'react-router-dom';

const Home: React.FC = () => {
  const skills = [
    { name: 'ESP32', level: 95, color: 'bg-blue-500' },
    { name: 'STM32', level: 90, color: 'bg-green-500' },
    { name: 'PLC Programming', level: 88, color: 'bg-purple-500' },
    { name: 'C/C++', level: 92, color: 'bg-red-500' },
    { name: 'MQTT/IoT', level: 85, color: 'bg-yellow-500' },
    { name: 'Modbus/CAN', level: 80, color: 'bg-indigo-500' },
  ];

  const projects = [
    {
      title: 'Умная система мониторинга',
      description: 'IoT система на ESP32 для мониторинга промышленного оборудования',
      tech: ['ESP32', 'MQTT', 'InfluxDB', 'Grafana'],
      image: '/api/placeholder/400/250',
      featured: true
    },
    {
      title: 'Контроллер автоматизации',
      description: 'ПЛК система для управления производственной линией',
      tech: ['STM32', 'Modbus RTU', 'HMI', 'SCADA'],
      image: '/api/placeholder/400/250',
      featured: true
    },
    {
      title: 'Беспроводная сенсорная сеть',
      description: 'Mesh-сеть датчиков на базе ESP32 для мониторинга окружающей среды',
      tech: ['ESP32', 'ESP-MESH', 'FreeRTOS', 'WebSocket'],
      image: '/api/placeholder/400/250',
      featured: true
    }
  ];

  const achievements = [
    '15+ завершенных проектов в области автоматизации',
    '5+ лет опыта программирования микроконтроллеров',
    'Сертификация по промышленным протоколам связи',
    'Опыт внедрения IoT решений в производство'
  ];

  return (
    <div className="min-h-screen bg-gray-50">
      <h1>Home Page</h1>
    </div>
  );
};

export default Home;
